            throw new ArgumentException("Session ID cannot be null or empty.", nameof(sessionId));

        string filePath = GetSessionFilePath(sessionId);
        if (File.Exists(filePath))
        {
            File.Delete(filePath);
            return true;
        }
        return false; // Session not found
    }

